option.value:
html {
    margin: 0;
    padding: 0;
    background: #181a1b;
    overscroll-behavior-y: none;
}

body {
    font-family: Arial, sans-serif;
    margin: 0;
    padding: 0;
    line-height: 1.6;
    color: #e0e0e0;
    overscroll-behavior-y: none;
    background-color: #181a1b;
    background-image:
        linear-gradient(rgba(24, 26, 27, 0.26), rgba(24, 26, 27, 0.26)),
        linear-gradient(90deg, rgba(255, 255, 255, 0.12) 0%, rgba(255, 255, 255, 0.02) 18%, rgba(255, 255, 255, 0.02) 82%, rgba(255, 255, 255, 0.12) 100%),
        url("imgs/background.jpg");
    background-size: cover;
    background-position: center;
    background-repeat: no-repeat;
    background-attachment: fixed;
    background-blend-mode: normal;
}

header {
    background-color: #23272a;
    color: #fff;
    padding: 1rem 0;
}

nav {
    display: flex;
    justify-content: space-between;
    align-items: center;
    max-width: 1200px;
    margin: 0 auto;
    padding: 0 2rem;
}

.logo {
    display: inline-flex;
    align-items: center;
    text-decoration: none;
    line-height: 0;
}

.logo img {
    width: 56px;
    height: 56px;
    display: block;
}

ul {
    list-style: none;
    display: flex;
    gap: 2rem;
}

a {
    color: #8ab4f8;
    text-decoration: none;
    transition: color 0.2s;
}

a:hover {
    color: #4f8cff;
    text-decoration: underline;
}

#hero {
    background-color: #23272a;
    padding: 4rem 2rem;
    text-align: center;
    border-bottom: 1px solid #222;
}

#hero h1 {
    font-size: 2.5rem;
    margin-bottom: 1rem;
    color: #fff;
}

#hero p {
    font-size: 1.2rem;
    color: #b0b0b0;
}

section {
    padding: 2rem;
    max-width: 1200px;
    margin: 0 auto;
    background: #23272a;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0,0,0,0.2);
    margin-bottom: 2rem;
}

h2 {
    text-align: center;
    margin-bottom: 2rem;
    color: #fff;
}

.project {
    margin-bottom: 2rem;
    padding: 1rem;
    border: 1px solid #333;
    border-radius: 5px;
    background: #181a1b;
}

footer {
    background-color: #23272a;
    color: #b0b0b0;
    text-align: center;
    padding: 1rem 0;
    border-top: 1px solid #222;
}

/* Fade-in animation for sections */
@keyframes fadeIn {
    from { opacity: 0; transform: translateY(40px); }
    to { opacity: 1; transform: translateY(0); }
}

section, header, footer {
    opacity: 0;
    animation: fadeIn 1s ease forwards;
}

header {
    animation-delay: 0.1s;
}
#hero {
    animation-delay: 0.2s;
}
#about {
    animation-delay: 0.3s;
}
#projects {
    animation-delay: 0.5s;
}
#contact {
    animation-delay: 0.6s;
}
footer {
    animation-delay: 0.7s;
}

/* Smooth hover transitions for buttons and cards */
.project {
    transition: box-shadow 0.3s, transform 0.3s;
}
.project:hover {
    box-shadow: 0 4px 24px rgba(138,180,248,0.15);
    transform: translateY(-6px) scale(1.03);
}

nav ul li a {
    color: #fff;
    text-decoration: none;
    transition: color 0.2s, background 0.2s, border-radius 0.2s;
}
nav ul li a:hover {
    background: #23272a;
    color: #4f8cff;
    border-radius: 6px;
    text-decoration: underline;
}

/* Make links in the contact section visible and styled */
#contact a {
    color: #8ab4f8; /* LinkedIn blue */
    text-decoration: underline;
    font-weight: bold;
    background: none;
}

#contact a:hover {
    color: #4f8cff;
}

/* Contact form styling */
.contact-form {
    max-width: 600px;
    margin: 2rem auto 0;
}

.form-group {
    margin-bottom: 1.5rem;
    display: flex;
    flex-direction: column;
}

.form-group label {
    color: #fff;
    margin-bottom: 0.5rem;
    font-weight: bold;
}

.form-group input,
.form-group textarea {
    padding: 0.75rem;
    background: #181a1b;
    border: 1px solid #333;
    border-radius: 4px;
    color: #e0e0e0;
    font-family: Arial, sans-serif;
    font-size: 1rem;
    transition: border-color 0.3s, box-shadow 0.3s;
}

.form-group input:focus,
.form-group textarea:focus {
    outline: none;
    border-color: #8ab4f8;
    box-shadow: 0 0 8px rgba(138,180,248,0.2);
}

.submit-btn {
    background: linear-gradient(135deg, #8ab4f8, #4f8cff);
    color: #fff;
    border: none;
    padding: 0.75rem 2rem;
    border-radius: 4px;
    font-size: 1rem;
    font-weight: bold;
    cursor: pointer;
    transition: transform 0.2s, box-shadow 0.2s;
}

.submit-btn:hover {
    transform: translateY(-2px);
    box-shadow: 0 4px 12px rgba(138,180,248,0.3);
}

.submit-btn:active {
    transform: translateY(0);
}

.stack-section {
    padding: 2.5rem 2rem;
}

.stack-container {
    max-width: 1000px;
    width: min(100%, 1000px);
    margin: 0 auto;
    padding: clamp(1.4rem, 3vw, 2.2rem);
    border: 1px solid #333;
    border-radius: 10px;
    background: #181a1b;
}

.cube-scene {
    --cube-size: 220px;
    display: grid;
    place-items: center;
    min-height: calc(var(--cube-size) * 1.8);
    perspective: 900px;
    perspective-origin: center;
    cursor: grab;
    user-select: none;
    touch-action: none;
}

.cube-scene.is-dragging {
    cursor: grabbing;
}

.stack-cube {
    position: relative;
    width: var(--cube-size);
    height: var(--cube-size);
    margin: 0;
    padding: 0;
    list-style: none;
    transform-style: preserve-3d;
    transform: rotateX(-16deg) rotateY(22deg);
    transition: transform 0.08s linear;
    will-change: transform;
}

.cube-scene.is-dragging .stack-cube {
    transition: none;
}

.cube-scene.is-inertia .stack-cube {
    transition: none;
}

.stack-cube li {
    position: absolute;
    inset: 0;
    margin: 0;
    display: grid;
    place-items: center;
    text-align: center;
    padding: 0.9rem;
    font-size: 1.05rem;
    font-weight: 600;
    color: #1f2328;
    border: 1px solid #d9d9d9;
    border-radius: 12px;
    background: #ffffff;
    box-shadow: 0 8px 18px rgba(0, 0, 0, 0.2);
    backface-visibility: hidden;
}

.stack-cube li:nth-child(1) { transform: rotateY(0deg) translateZ(calc(var(--cube-size) / 2)); }
.stack-cube li:nth-child(2) { transform: rotateY(90deg) translateZ(calc(var(--cube-size) / 2)); }
.stack-cube li:nth-child(3) { transform: rotateY(180deg) translateZ(calc(var(--cube-size) / 2)); }
.stack-cube li:nth-child(4) { transform: rotateY(-90deg) translateZ(calc(var(--cube-size) / 2)); }
.stack-cube li:nth-child(5) { transform: rotateX(90deg) translateZ(calc(var(--cube-size) / 2)); }
.stack-cube li:nth-child(6) { transform: rotateX(-90deg) translateZ(calc(var(--cube-size) / 2)); }

@media (max-width: 700px) {
    .cube-scene {
        --cube-size: 170px;
        min-height: calc(var(--cube-size) * 1.95);
    }

    .stack-cube li {
        font-size: 0.92rem;
        border-radius: 10px;
    }
}

#stack {
    animation-delay: 0.4s;
}

#projects {
    animation-delay: 0.5s;
}

#contact {
    animation-delay: 0.6s;
}

footer {
    animation-delay: 0.7s;
}

