.stack-container {
    max-width: 1000px;
    width: min(100%, 1000px);
    margin: 0 auto;
    padding: clamp(1.4rem, 3vw, 2.2rem);
    border: 1px solid #333;
    border-radius: 10px;
    background: #181a1b;
}

.stack-layout {
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: clamp(1rem, 2.2vw, 2rem);
    align-items: center;
}

.cube-scene {
    --cube-size: 220px;
    display: grid;
    place-items: center;
    min-height: calc(var(--cube-size) * 1.8);
    perspective: 900px;
    perspective-origin: center;
    cursor: grab;
    user-select: none;
    touch-action: none;
}

.stack-faces {
    min-height: calc(var(--cube-size) * 1.2);
    display: flex;
    flex-direction: column;
    justify-content: center;
}

.stack-faces h3 {
    margin: 0 0 1rem;
    color: #fff;
    font-size: 1.2rem;
}

.stack-faces-list {
    margin: 0;
    padding: 0;
    list-style: none;
    display: grid;
    gap: 0.65rem;
}

.stack-faces-list li {
    padding: 0.65rem 0.8rem;
    border: 1px solid #3a3f44;
    border-radius: 8px;
    background: #222629;
    color: #e8f0ff;
    font-weight: 600;
}

.cube-scene.is-dragging {
    cursor: grabbing;
}

.stack-cube {
    position: relative;
    width: var(--cube-size);
    height: var(--cube-size);
    margin: 0;
    padding: 0;
    list-style: none;
    transform-style: preserve-3d;
    transform: rotateX(-16deg) rotateY(22deg);
    transition: transform 0.08s linear;
    will-change: transform;
}

.cube-scene.is-dragging .stack-cube {
    transition: none;
}

.cube-scene.is-inertia .stack-cube {
    transition: none;
}

.stack-cube li {
    position: absolute;
    inset: 0;
    margin: 0;
    display: grid;
    place-items: center;
    text-align: center;
    padding: 0.9rem;
    font-size: 1.05rem;
    font-weight: 600;
    color: #e8f0ff;
    border: 1px solid #3a3f44;
    border-radius: 12px;
    background: linear-gradient(135deg, rgba(32, 35, 38, 0.95), rgba(25, 28, 31, 0.95));
    box-shadow: 0 4px 14px rgba(0, 0, 0, 0.28);
    backface-visibility: hidden;
}

.stack-cube li:nth-child(1) { transform: rotateY(0deg) translateZ(calc(var(--cube-size) / 2)); }
.stack-cube li:nth-child(2) { transform: rotateY(90deg) translateZ(calc(var(--cube-size) / 2)); }
.stack-cube li:nth-child(3) { transform: rotateY(180deg) translateZ(calc(var(--cube-size) / 2)); }
.stack-cube li:nth-child(4) { transform: rotateY(-90deg) translateZ(calc(var(--cube-size) / 2)); }
.stack-cube li:nth-child(5) { transform: rotateX(90deg) translateZ(calc(var(--cube-size) / 2)); }
.stack-cube li:nth-child(6) { transform: rotateX(-90deg) translateZ(calc(var(--cube-size) / 2)); }

@media (max-width: 700px) {
    .stack-layout {
        grid-template-columns: 1fr;
    }

    .cube-scene {
        --cube-size: 170px;
        min-height: calc(var(--cube-size) * 1.95);
    }

    .stack-faces {
        min-height: auto;
    }

    .stack-faces h3 {
        text-align: center;
    }

    .stack-cube li {
        font-size: 0.92rem;
        border-radius: 10px;
    }
}

#stack {
    animation-delay: 0.4s;
}

#projects {
    animation-delay: 0.5s;
}

#contact {
    animation-delay: 0.6s;
}

footer {
    animation-delay: 0.7s;
}
